package com.arkeomag.pro; import android.content.*;import android.view.*;import android.graphics.*;import java.util.*;
public class HeatmapView extends View{Paint p=new Paint(1);int n=20;ArrayList<InterpolationEngine.P> pts=new ArrayList<>();float cursor=0; public HeatmapView(Context c){super(c);} public void addPoint(float v){float x=(pts.size()%n)/(float)(n-1);float y=(pts.size()/n)/(float)(n-1);if(pts.size()>=n*n)pts.clear();pts.add(new InterpolationEngine.P(x,y,Math.min(1,v/40f)));invalidate();} protected void onDraw(Canvas c){int w=getWidth(),h=getHeight();p.setColor(Color.rgb(8,15,28));c.drawRoundRect(0,0,w,h,28,28,p);float[][] g=InterpolationEngine.idw(pts,n);float cell=Math.min(w,h)/(float)n;float ox=(w-cell*n)/2,oy=(h-cell*n)/2;for(int i=0;i<n;i++)for(int j=0;j<n;j++){p.setColor(Palette.color(g[i][j]));c.drawRect(ox+i*cell,oy+j*cell,ox+(i+1)*cell,oy+(j+1)*cell,p);}p.setStyle(Paint.Style.STROKE);p.setColor(Color.argb(70,255,255,255));p.setStrokeWidth(1);for(int i=0;i<=n;i++){c.drawLine(ox+i*cell,oy,ox+i*cell,oy+n*cell,p);c.drawLine(ox,oy+i*cell,ox+n*cell,oy+i*cell,p);}p.setStyle(Paint.Style.FILL);} }
